int longestIncreasingSubsequence(const std::vector<int>& sequence) {
    int n = sequence.size();
    std::vector<int> lis(n, 1); // Initialize LIS values for all indexes as 1

    // Compute optimized LIS values in bottom up manner
    for (int i = 1; i < n; i++) {
