T0 = input('Enter the initial temperature (T0): ');
alpha = input('Enter the thermal diffusivity (α): ');
dx = input('Enter the spatial step size (dx): ');
dt = input('Enter the time step size (dt): ');
time_steps = input('Enter the number of time steps (n): ');

% Boundary and initial conditions
