import Foundation

/// Filters an array of strings to include only those containing at least one numeric digit.
///
/// - Parameter strings: An array of strings to be filtered.
/// - Returns: A new array containing only the strings with at least one digit.
func filterStringsWithDigits(strings: [String]) -> [String] {
    let filteredArray = strings.filter { string in
        // Check if the string contains any numeric digit
        let containsDigit = string.range(of: #"[0-9]"#, options: .regularExpression) != nil
        return containsDigit
    }

    return filteredArray
}

// Example usage:
let inputStrings = ["apple", "orange123", "banana", "123grape", "cherry456"]
let filteredStrings = filterStringsWithDigits(strings: inputStrings)
print(filteredStrings) // Output: ["orange123", "123grape", "cherry456"]
```

