```cpp
#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

// Function to compute the length of the Longest Increasing Subsequence
int longestIncreasingSubsequenceLength(const vector<int>& sequence) {
    int n = sequence.size();
    if (n == 0) return 0;

    // li[i] stores the length of the longest increasing subsequence ending with sequence[i]
    vector<int> li(n, 1);

    // Compute the longest increasing subsequence length for each element
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (sequence[i] > sequence[j]) {
                li[i] = max(li[i], li[j] + 1);
            }
        }
    }

    // The length of the longest increasing subsequence is the maximum value in li
    return *max_element(li.begin(), li.end());
}

int main() {
    int n;
    cout << "Enter the number of elements in the sequence: ";
    cin >> n;

    vector<int> sequence(n);
    cout << "Enter " << n << " integers: ";
    for (int i = 0; i < n; i++) {
        cin >> sequence[i];
    }

    int lisLength = longestIncreasingSubsequenceLength(sequence);
    cout << "Length of the longest increasing subsequence: " << lisLength << endl;

    return 0;
}
```

### Explanation:

1. **Input Handling**:
   - The program first asks the user for the number of elements in the sequence.
   - Then, it prompts the user to enter the sequence of integers.

2. **Dynamic Programming**:
   - We use a vector `li` to store the length of the longest increasing subsequence that ends with each element in the input sequence.
   - For each element in the sequence, we check all previous elements to see if they can form an increasing subsequence with the current element.
