Certainly! Below is a C++ program that uses dynamic programming to find the length of the longest increasing subsequence (LIS) in a given sequence of integers. The program will accept user input for the length of the sequence and the values in the sequence, and then it will output the length of the longest increasing subsequence.

```cpp
#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

// Function to find the length of the longest increasing subsequence
int longestIncreasingSubsequence(const vector<int>& nums) {
    int n = nums.size();
    if (n == 0) return 0;

    // Initialize the dp array
    vector<int> dp(n, 1);

    // Compute the length of the longest increasing subsequence
    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < i; ++j) {
            if (nums[i] > nums[j]) {
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }

    // The length of the longest increasing subsequence is the maximum value in dp
    return *max_element(dp.begin(), dp.end());
}

int main() {
    int n;
    cout << "Enter the length of the sequence: ";
    cin >> n;

    vector<int> sequence(n);
    cout << "Enter the sequence of integers: ";
    for (int i = 0; i < n; ++i) {
        cin >> sequence[i];
    }

    int lisLength = longestIncreasingSubsequence(sequence);
    cout << "Length of the longest increasing subsequence: " << lisLength << endl;

    return 0;
}
```

