        boolean capitalizeNext = true;

        for (char c : input.toCharArray()) {
            if (c == ' ') {
                capitalizeNext = true;
            } else {
                if (capitalizeNext) {
                    titleCase.append(Character.toUpperCase(c));
                    capitalizeNext = false;
                } else {
                    titleCase.append(Character.toLowerCase(c));
                }
            }
        }

        return titleCase.toString();
    }
}
