import Foundation

/// Filters an array of strings to include only those that contain at least one digit.
/// - Parameter strings: An array of strings to be filtered.
/// - Returns: A new array containing only strings that have at least one digit.
func filterStringsWithDigits(strings: [String]) -> [String] {
    var result: [String] = []

    for string in strings {
        // Check if the string contains any digit
        if string.range(of: #"[0-9]"#, options: .regularExpression) != nil {
            result.append(string)
        }
    }

    return result
}

