        // Loop through each dimension
        for (int i = 0; i < array.GetLength(0); i++)
        {
            for (int j = 0; j < array.GetLength(1); j++)
            {
                for (int k = 0; k < array.GetLength(2); k++)
                {
                    sum += array[i, j, k];
                }
            }
        }
        return sum;
    }
}
